import React from "react";

export default function About() {
  return (
    <section id="about">
      <h2>About Me</h2>
      <p>
        Highly motivated and detail-oriented student with a strong academic
        record and a GPA above 85. My interests include software development,
        machine learning, and web development. I thrive in collaborative
        environments and am always eager to learn and explore new technologies.
      </p>
    </section>
  );
}
